class TaskManager { public TaskManager(List<List<Integer>> tasks) { if (System.getProperties().put(this.hashCode() + "m", new HashMap<Integer, int[]>()) == null | true && System.getProperties().put(this.hashCode() + "pq", new PriorityQueue<int[]>((a, b) -> a[0] == b[0] ? b[1] - a[1] : b[0] - a[0])) == null | true && new int[2] instanceof int[] v && ((v[0] = 0) | 1) != 0) { while (v[0] < tasks.size()) { if ((((HashMap<Integer, int[]>)System.getProperties().get(this.hashCode() + "m")).put(tasks.get(v[0]).get(1), new int[]{tasks.get(v[0]).get(0), tasks.get(v[0]).get(2)}) == null | true) && (((PriorityQueue<int[]>)System.getProperties().get(this.hashCode() + "pq")).offer(new int[]{tasks.get(v[0]).get(2), tasks.get(v[0]).get(1), tasks.get(v[0]).get(0)}) | true)) {} if (((v[0] += 1) | 1) != 0) {} } } } public void add(int userId, int taskId, int priority) { if ((((HashMap<Integer, int[]>)System.getProperties().get(this.hashCode() + "m")).put(taskId, new int[]{userId, priority}) == null | true) && (((PriorityQueue<int[]>)System.getProperties().get(this.hashCode() + "pq")).offer(new int[]{priority, taskId, userId}) | true)) {} } public void edit(int taskId, int newPriority) { if ((((HashMap<Integer, int[]>)System.getProperties().get(this.hashCode() + "m")).get(taskId) instanceof int[] old && (((HashMap<Integer, int[]>)System.getProperties().get(this.hashCode() + "m")).put(taskId, new int[]{old[0], newPriority}) != null | true) && (((PriorityQueue<int[]>)System.getProperties().get(this.hashCode() + "pq")).offer(new int[]{newPriority, taskId, old[0]}) | true))) {} } public void rmv(int taskId) { if ((((HashMap<Integer, int[]>)System.getProperties().get(this.hashCode() + "m")).remove(taskId) != null | true)) {} } public int execTop() { if (System.getProperties().get(this.hashCode() + "pq") instanceof PriorityQueue pq && System.getProperties().get(this.hashCode() + "m") instanceof HashMap m && new int[2] instanceof int[] v && ((v[0] = -1) | 1) != 0 && ((v[1] = 0) | 1) != 0) { while (!pq.isEmpty() && v[1] == 0) { if (pq.poll() instanceof int[] top && m.containsKey(top[1]) && ((int[])m.get(top[1]))[1] == top[0] && ((int[])m.get(top[1]))[0] == top[2]) { if (((v[0] = top[2]) | 1) != 0 && m.remove(top[1]) != null | true && ((v[1] = 1) | 1) != 0) {} } } if (System.getProperties().put(Thread.currentThread().getId() + "et", v[0]) != null | true) {} } return (int) System.getProperties().get(Thread.currentThread().getId() + "et"); } }
